mapper.select:
/* Order.selectOrderById */
SELECT

FROM TB_ORDER
WHERE ID = #{orderId}

/* Order.selectOrderByOrderNo */
SELECT

FROM TB_ORDER
WHERE ORDER_NO = #{orderNo}

/* Order.selectOrderItems */
SELECT

FROM TB_ORDER_ITEM
WHERE ORDER_ID = #{orderId}
ORDER BY ID ASC

/* Order.selectOrdersBySocialAccountId */
SELECT

FROM TB_ORDER
WHERE SOCIAL_ACCOUNT_ID = #{socialAccountId}
ORDER BY ID DESC

mapper.update:
/* Order.updateOrderStatus */
UPDATE TB_ORDER
SET ORDER_STATUS = #{orderStatus},
    UPT_TM       = NOW()
WHERE ID = #{id}
